# --- Helper Functions ---

def aggregate_labels_for_image(image_id: str) -> Optional[AggregationResult]:
    """Aggregate labels for a single image using majority voting."""
    if image_id not in annotations_store or len(annotations_store[image_id]) == 0:
        return None

    labels = [ann["label"] for ann in annotations_store[image_id]]
    vote_counts = dict(Counter(labels))
    total_votes = len(labels)

    # Majority voting
    majority_label = max(vote_counts, key=vote_counts.get)
    confidence = vote_counts[majority_label] / total_votes

    result = AggregationResult(
        image_id=image_id,
        aggregated_label=majority_label,
        confidence=confidence,
        vote_counts=vote_counts,
        total_votes=total_votes,
    )

    # Store aggregated result
    aggregated_labels[image_id] = {
        "label": majority_label,
        "confidence": confidence,
        "vote_counts": vote_counts,
    }

    return result


def extract_features_from_bytes(image_bytes: bytes) -> np.ndarray:
    """Extract simple features from image bytes for training/prediction."""
    try:
        from PIL import Image
        img = Image.open(BytesIO(image_bytes)).convert("RGB")
        img = img.resize((64, 64))
        arr = np.array(img, dtype=np.float32) / 255.0

        features = []
        # Channel means and stds
        for c in range(3):
            channel = arr[:, :, c]
            features.extend([
                channel.mean(),
                channel.std(),
                np.median(channel),
                channel.min(),
                channel.max(),
            ])

        # Quadrant features
        h, w = arr.shape[:2]
        for qi in range(2):
            for qj in range(2):
                quadrant = arr[qi * h // 2:(qi + 1) * h // 2, qj * w // 2:(qj + 1) * w // 2]
                features.extend([quadrant.mean(), quadrant.std()])

        # Flatten a downsampled version
        small = np.array(img.resize((8, 8)), dtype=np.float32).flatten() / 255.0
        features.extend(small.tolist())

        return np.array(features, dtype=np.float32)
    except ImportError:
        # Fallback: use raw bytes statistics
        data = np.frombuffer(image_bytes[:4096], dtype=np.uint8).astype(np.float32)
        if len(data) < 4096:
            data = np.pad(data, (0, 4096 - len(data)))
        features = []
        chunk_size = 256
        for i in range(0, len(data), chunk_size):
            chunk = data[i:i + chunk_size]
            features.extend([chunk.mean(), chunk.std(), np.median(chunk)])
        return np.array(features[:200], dtype=np.float32)


