@app.post("/annotations", response_model=AnnotationResponse)
def submit_annotation(request: AnnotationRequest):
    """Submit a label annotation for an image from an annotator."""
    if request.image_id not in image_store:
        raise HTTPException(status_code=404, detail=f"Image {request.image_id} not found")

    annotation_id = str(uuid.uuid4())
    timestamp = datetime.utcnow().isoformat()

    annotation = {
        "annotation_id": annotation_id,
        "annotator_id": request.annotator_id,
        "label": request.label,
        "timestamp": timestamp,
    }

    annotations_store[request.image_id].append(annotation)
    label_classes.add(request.label)

    # Re-aggregate after new annotation
    aggregate_labels_for_image(request.image_id)

    return AnnotationResponse(
        annotation_id=annotation_id,
        image_id=request.image_id,
        annotator_id=request.annotator_id,
        label=request.label,
        timestamp=timestamp,
        total_annotations_for_image=len(annotations_store[request.image_id]),
    )


@app.post("/annotations/bulk")
def submit_bulk_annotations(request: BulkAnnotationRequest):
    """Submit multiple annotations at once."""
    results = []
    errors = []

    for ann in request.annotations:
        if ann.image_id not in image_store:
            errors.append({"image_id": ann.image_id, "error": "Image not found"})
            continue

        annotation_id = str(uuid.uuid4())
        timestamp = datetime.utcnow().isoformat()

        annotation = {
            "annotation_id": annotation_id,
            "annotator_id": ann.annotator_id,
            "label": ann.label,
            "timestamp": timestamp,
        }

        annotations_store[ann.image_id].append(annotation)
        label_classes.add(ann.label)
        aggregate_labels_for_image(ann.image_id)

        results.append({
            "annotation_id": annotation_id,
            "image_id": ann.image_id,
            "annotator_id": ann.annotator_id,
            "label": ann.label,
        })

    return {
        "submitted": len(results),
        "errors": len(errors),
        "results": results,
        "error_details": errors,
    }


