@app.post("/aggregate/{image_id}", response_model=AggregationResult)
def aggregate_single_image(image_id: str):
    """Aggregate labels for a single image using majority voting."""
    if image_id not in image_store:
        raise HTTPException(status_code=404, detail=f"Image {image_id} not found")

    result = aggregate_labels_for_image(image_id)
    if result is None:
        raise HTTPException(status_code=400, detail=f"No annotations found for image {image_id}")

    return result


@app.post("/aggregate/all")
def aggregate_all_images():
    """Aggregate labels for all images using majority voting."""
    results = []
    skipped = []

    for image_id in image_store:
        result = aggregate_labels_for_image(image_id)
        if result:
            results.append(result.dict())
        else:
            skipped.append(image_id)

    return {
        "aggregated": len(results),
        "skipped": len(skipped),
        "skipped_image_ids": skipped,
        "results": results,
    }


