@app.get("/stats")
def get_system_stats():
    """Get overall system statistics."""
    total_images = len(image_store)
    total_annotations = sum(len(anns) for anns in annotations_store.values())
    total_aggregated = len(aggregated_labels)

    # Annotator stats
    annotator_counts = Counter()
    for anns in annotations_store.values():
        for ann in anns:
            annotator_counts[ann["annotator_id"]] += 1

    # Label distribution
    label_dist = Counter()
    for agg in aggregated_labels.values():
        label_dist[agg["label"]] += 1

    # Average confidence
    confidences = [agg["confidence"] for agg in aggregated_labels.values()]
    avg_confidence = np.mean(confidences) if confidences else 0.0

    # Images needing more annotations (< 3 annotations)
    images_needing_annotations = sum(
        1 for image_id in image_store
        if len(annotations_store.get(image_id, [])) < 3
    )

    return {
        "total_images": total_images,
        "total_annotations": total_annotations,
        "total_aggregated_labels": total_aggregated,
        "total_annotators": len(annotator_counts),
        "total_label_classes": len(label_classes),
        "label_classes": sorted(list(label_classes)),
        "label_distribution": dict(label_dist),
        "average_confidence": round(float(avg_confidence), 4),
        "annotations_per_image_avg": round(total_annotations / total_images, 2) if total_images > 0 else 0,
        "images_needing_annotations": images_needing_annotations,
        "annotator_contributions": dict(annotator_counts),
        "model_trained": model_store["model"] is not None,
        "model_trained_at": model_store["trained_at"],
        "model_num_samples": model_store["num_samples"],
    }


@app.get("/annotators/{annotator_id}/stats", response_model=AnnotatorStats)
def get_annotator_stats(annotator_id: str):
    """Get statistics for a specific annotator."""
    total_annotations = 0
    images_annotated = []
    labels_given = []

    for image_id, anns in annotations_store.items():
        for ann in anns:
            if ann["annotator_id"] == annotator_id:
                total_annotations += 1
                if image_id not in images_annotated:
                    images_annotated.append(image_id)
                labels_given.append(ann["label"])

    if total_annotations == 0:
        raise HTTPException(status_code=404, detail=f"Annotator {annotator_id} not found")

    label_distribution = dict(Counter(labels_given))

    # Calculate agreement rate with majority vote
    agreements = 0
    compared = 0
    for image_id in images_annotated:
        if image_id in aggregated_labels:
            agg_label = aggregated_labels[image_id]["label"]
            for ann in annotations_store[image_id]:
                if ann["annotator_id"] == annotator_id:
                    compared += 1
                    if ann["label"] == agg_label:
                        agreements += 1

    agreement_rate = agreements / compared if compared > 0 else None

    return AnnotatorStats(
        annotator_id=annotator_id,
        total_annotations=total_annotations,
        images_annotated=images_annotated,
        label_distribution=label_distribution,
        agreement_rate=round(agreement_rate, 4) if agreement_rate is not None else None,
    )


@app.post("/train", response_model=TrainingResponse)
def train_model(request: TrainingRequest = TrainingRequest()):
    """Train a model on the aggregated labeled data without validation."""
    from sklearn.ensemble import RandomForestClassifier
    from sklearn.preprocessing import LabelEncoder

    # Collect training data
    X = []
    y = []

    for image_id, agg in aggregated_labels.items():
        # Filter by minimum votes and confidence
        num_votes = sum(agg["vote_counts"].values())
        if num_votes < request.min_votes:
            continue
        if agg["confidence"] < request.min_confidence:
            continue

        if image_id in image_store:
            try:
                features = extract_features_from_bytes(image_store[image_id]["data"])
                X.append(features)
                y.append(agg["label"])
            except Exception as e:
                print(f"Error extracting features for {image_id}: {e}")
                continue

    if len(X) == 0:
        raise HTTPException(
            status_code=400,
            detail="No training data available. Upload images, annotate them, and aggregate labels first.",
        )

    if len(set(y)) < 2:
        raise HTTPException(
            status_code=400,
            detail=f"Need at least 2 classes to train. Currently have {len(set(y))} class(es): {list(set(y))}",
        )

    X = np.array(X)
    le = LabelEncoder()
    y_encoded = le.fit_transform(y)

    # Train without validation
    clf = RandomForestClassifier(
        n_estimators=100,
        max_depth=None,
        min_samples_split=2,
        random_state=42,
        n_jobs=-1,
    )
    clf.fit(X, y_encoded)

    # Store model
    trained_at = datetime.utcnow().isoformat()
    model_store["model"] = clf
    model_store["label_encoder"] = le
    model_store["trained_at"] = trained_at
    model_store["num_samples"] = len(X)

    classes = le.classes_.tolist()

    return TrainingResponse(
        status="success",
        num_training_samples=len(X),
        num_classes=len(classes),
        classes=classes,
        trained_at=trained_at,
        message=f"Model trained successfully on {len(X)} samples with {len(classes)} classes. No validation performed.",
    )


@app.post("/predict/{image_id}", response_model=PredictionResponse)
def predict_image(image_id: str):
    """Predict the label for an image using the trained model."""
    if model_store["model"] is None:
        raise HTTPException(status_code=400, detail="No model trained yet. Call /train first.")

    if image_id not in image_store:
        raise HTTPException(status_code=404, detail=f"Image {image_id} not found")

    try:
        features = extract_features_from_bytes(image_store[image_id]["data"])
    except Exception as e:
        raise HTTPException(status_code=500, detail=f"Error extracting features: {e}")

    clf = model_store["model"]
    le = model_store["label_encoder"]

    features_2d = features.reshape(1, -1)
    prediction = clf.predict(features_2d)[0]
    probabilities = clf.predict_proba(features_2d)[0]

    predicted_label = le.inverse_transform([prediction])[0]
    all_probs = {label: round(float(prob), 4) for label, prob in zip(le.classes_, probabilities)}
    confidence = float(max(probabilities))

    return PredictionResponse(
        image_id=image_id,
        predicted_label=predicted_label,
        confidence=round(confidence, 4),
        all_probabilities=all_probs,
    )


@app.post("/predict/batch")
def predict_batch(image_ids: list[str]):
    """Predict labels for multiple images."""
    if model_store["model"] is None:
        raise HTTPException(status_code=400, detail="No model trained yet. Call /train first.")

    results = []
    errors = []

    clf = model_store["model"]
    le = model_store["label_encoder"]

    for image_id in image_ids:
        if image_id not in image_store:
            errors.append({"image_id": image_id, "error": "Image not found"})
            continue

        try:
            features = extract_features_from_bytes(image_store[image_id]["data"])
            features_2d = features.reshape(1, -1)
            prediction = clf.predict(features_2d)[0]
            probabilities = clf.predict_proba(features_2d)[0]

            predicted_label = le.inverse_transform([prediction])[0]
            confidence = float(max(probabilities))

            results.append({
                "image_id": image_id,
                "predicted_label": predicted_label,
                "confidence": round(confidence, 4),
            })
        except Exception as e:
            errors.append({"image_id": image_id, "error": str(e)})

    return {
        "predictions": results,
        "errors": errors,
        "total_predicted": len(results),
        "total_errors": len(errors),
    }


@app.get("/inter_annotator_agreement")
def inter_annotator_agreement():
    """Calculate inter-annotator agreement statistics."""
    # Find images with multiple annotators
    multi_annotated = {}
    for image_id, anns in annotations_store.items():
        if len(anns) >= 2:
            multi_annotated[image_id] = anns

    if not multi_annotated:
        return {"message": "No images with multiple annotations found", "agreement_stats": {}}

    total_pairs = 0
    agreeing_pairs = 0

    per_image_agreement = {}
    for image_id, anns in multi_annotated.items():
        labels = [ann["label"] for ann in anns]
        pairs = 0
        agrees = 0
        for i in range(len(labels)):
            for j in range(i + 1, len(labels)):
                pairs += 1
                if labels[i] == labels[j]:
                    agrees += 1
        total_pairs += pairs
        agreeing_pairs += agrees
        per_image_agreement[image_id] = round(agrees / pairs, 4) if pairs > 0 else 1.0

    overall_agreement = agreeing_pairs / total_pairs if total_pairs > 0 else 0.0

    return {
        "overall_pairwise_agreement": round(overall_agreement, 4),
        "total_multi_annotated_images": len(multi_annotated),
        "total_annotation_pairs": total_pairs,
        "agreeing_pairs": agreeing_pairs,
        "per_image_agreement": per_image_agreement,
    }


@app.post("/export/training_data")
def export_training_data(min_votes: int = 1, min_confidence: float = 0.0):
    """Export aggregated training data as JSON."""
    training_data = []

    for image_id, agg in aggregated_labels.items():
        num_votes = sum(agg["vote_counts"].values())
        if num_votes < min_votes:
            continue
        if agg["confidence"] < min_confidence:
            continue

        if image_id in image_store:
            training_data.append({
                "image_id": image_id,
                "filename": image_store[image_id]["filename"],
                "label": agg["label"],
                "confidence": agg["confidence"],
                "vote_counts": agg["vote_counts"],
                "num_annotations": num_votes,
                "image_base64": base64.b64encode(image_store[image_id]["data"]).decode("utf-8"),
            })

    return {
        "total_samples": len(training_data),
        "filters": {"min_votes": min_votes, "min_confidence": min_confidence},
        "data": training_data,
    }


# --- Demo data seeding endpoint ---

@app.post("/demo/seed")
def seed_demo_data():
    """Seed the system with demo data for testing."""
    import random

    demo_labels = ["cat", "dog", "bird", "car", "tree"]
    annotators = ["annotator_1", "annotator_2", "annotator_3", "annotator_4", "annotator_5"]

    created_images = []

    for i in range(10):
        image_id = str(uuid.uuid4())
        # Create a synthetic image (random bytes that form a valid-ish image)
        try:
            from PIL import Image as PILImage
            img = PILImage.fromarray(
                np.random.randint(0, 255, (64, 64, 3), dtype=np.uint8)
            )
            buf = BytesIO()
            img.save(buf, format="PNG")
            image_data = buf.getvalue()
        except ImportError:
            image_data = bytes(np.random.randint(0, 255, 1024, dtype=np.uint8))

        image_store[image_id] = {
            "filename": f"demo_image_{i}.png",
            "data": image_data,
            "uploaded_at": datetime.utcnow().isoformat(),
        }
        annotations_store[image_id] = []

        # Assign a "true" label and have annotators mostly agree
        true_label = random.choice(demo_labels)

        num_annotators = random.randint(3, 5)
        selected_annotators = random.sample(annotators, num_annotators)

        for annotator_id in selected_annotators:
            # 80% chance of agreeing with true label
            if random.random() < 0.8:
                label = true_label
            else:
                label = random.choice(demo_labels)

            annotation = {
                "annotation_id": str(uuid.uuid4()),
                "annotator_id": annotator_id,
                "label": label,
                "timestamp": datetime.utcnow().isoformat(),
            }
            annotations_store[image_id].append(annotation)
            label_classes.add(label)

        aggregate_labels_for_image(image_id)
        created_images.append({
            "image_id": image_id,
            "true_label": true_label,
            "num_annotations": num_annotators,
            "aggregated_label": aggregated_labels[image_id]["label"],
        })

    return {
        "message": "Demo data seeded successfully",
        "images_created": len(created_images),
        "details": created_images,
    }


